import { useState, useEffect, useMemo } from "react";
import * as XLSX from "xlsx";
import {
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend,
  ResponsiveContainer, ReferenceLine, Area, AreaChart, ComposedChart, Line, LineChart, Cell
} from "recharts";

const KHULNA_LAT = 22.8098;
const KHULNA_LON = 89.5644;
const MONTHS = ["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"];

// ── FORMULAS ──────────────────────────────────────────────────────────────────

// Stull (2011) Wet Bulb Temperature formula
function calcWetBulb(T, RH) {
  if (T == null || RH == null) return null;
  const Tw = T * Math.atan(0.151977 * Math.pow(RH + 8.313659, 0.5))
    + Math.atan(T + RH)
    - Math.atan(RH - 1.676331)
    + 0.00391838 * Math.pow(RH, 1.5) * Math.atan(0.023101 * RH)
    - 4.686035;
  return parseFloat(Tw.toFixed(2));
}

// Vapor pressure (hPa) from T and RH
function calcVaporPressure(T, RH) {
  if (T == null || RH == null) return null;
  const es = 6.112 * Math.exp((17.67 * T) / (T + 243.5));
  return (RH / 100) * es;
}

// Simplified outdoor WBGT (Liljegren approximation without globe temp)
// WBGT ≈ 0.567·T + 0.393·e + 3.94  (Bernard & Pourmoghani 1999)
function calcWBGT(T, RH) {
  if (T == null || RH == null) return null;
  const e = calcVaporPressure(T, RH);
  return parseFloat((0.567 * T + 0.393 * e + 3.94).toFixed(2));
}

// Heat stroke risk from WBGT
function getWBGTRisk(wbgt) {
  if (wbgt == null) return { level: "Unknown", color: "#6b7280", bg: "#1f2937", emoji: "❓", index: 0 };
  if (wbgt < 28)  return { level: "Safe",     color: "#4ade80", bg: "#052e16", emoji: "🟢", index: 1 };
  if (wbgt < 32)  return { level: "Caution",  color: "#facc15", bg: "#1c1917", emoji: "🟡", index: 2 };
  if (wbgt < 35)  return { level: "Danger",   color: "#f97316", bg: "#1c0a00", emoji: "🟠", index: 3 };
  return              { level: "Extreme",  color: "#ef4444", bg: "#1c0000", emoji: "🔴", index: 4 };
}

// Wet bulb risk (Raymond et al. 2020 thresholds)
function getTwRisk(tw) {
  if (tw == null) return { level: "Unknown", color: "#6b7280" };
  if (tw < 26)  return { level: "Safe",           color: "#4ade80" };
  if (tw < 28)  return { level: "Uncomfortable",  color: "#a3e635" };
  if (tw < 30)  return { level: "Stressful",      color: "#facc15" };
  if (tw < 32)  return { level: "Very Stressful", color: "#f97316" };
  if (tw < 35)  return { level: "Dangerous",      color: "#ef4444" };
  return              { level: "LETHAL LIMIT",    color: "#dc2626" };
}

function avg(arr) {
  const valid = arr.filter(v => v != null);
  if (!valid.length) return null;
  return parseFloat((valid.reduce((a, b) => a + b, 0) / valid.length).toFixed(2));
}

function groupByMonth(rows) {
  const monthly = {};
  rows.forEach(r => {
    const [year, month] = r.date.split("-");
    const key = `${year}-${month}`;
    if (!monthly[key]) monthly[key] = { label: `${MONTHS[parseInt(month)-1]} ${year}`, maxT:[], minT:[], meanT:[], hum:[], sol:[], tw:[], wbgt:[], dangerDays:0, extremeDays:0, total:0 };
    if (r.maxTemp != null)  monthly[key].maxT.push(r.maxTemp);
    if (r.minTemp != null)  monthly[key].minT.push(r.minTemp);
    if (r.meanTemp != null) monthly[key].meanT.push(r.meanTemp);
    if (r.humidity != null) monthly[key].hum.push(r.humidity);
    if (r.solar != null)    monthly[key].sol.push(r.solar);
    if (r.wetBulb != null)  monthly[key].tw.push(r.wetBulb);
    if (r.wbgt != null)     monthly[key].wbgt.push(r.wbgt);
    monthly[key].total++;
    if (r.wbgt >= 32) monthly[key].dangerDays++;
    if (r.wbgt >= 35) monthly[key].extremeDays++;
  });
  return Object.entries(monthly).map(([k, v]) => ({
    key: k, label: v.label,
    maxTemp: avg(v.maxT), minTemp: avg(v.minT),
    meanTemp: avg(v.meanT), humidity: avg(v.hum),
    solar: avg(v.sol), wetBulb: avg(v.tw), wbgt: avg(v.wbgt),
    dangerDays: v.dangerDays, extremeDays: v.extremeDays, totalDays: v.total,
  }));
}

function groupByYear(rows) {
  const yearly = {};
  rows.forEach(r => {
    const year = r.date.split("-")[0];
    if (!yearly[year]) yearly[year] = { tw:[], wbgt:[], dangerDays:0, extremeDays:0, cautionDays:0, total:0 };
    if (r.wetBulb != null) yearly[year].tw.push(r.wetBulb);
    if (r.wbgt != null)    yearly[year].wbgt.push(r.wbgt);
    yearly[year].total++;
    if (r.wbgt >= 28 && r.wbgt < 32) yearly[year].cautionDays++;
    if (r.wbgt >= 32 && r.wbgt < 35) yearly[year].dangerDays++;
    if (r.wbgt >= 35) yearly[year].extremeDays++;
  });
  return Object.entries(yearly).sort().map(([year, v]) => ({
    year, avgTw: avg(v.tw), avgWbgt: avg(v.wbgt),
    cautionDays: v.cautionDays, dangerDays: v.dangerDays, extremeDays: v.extremeDays, totalDays: v.total,
  }));
}

// ── TOOLTIP ───────────────────────────────────────────────────────────────────
const CustomTooltip = ({ active, payload, label }) => {
  if (!active || !payload?.length) return null;
  return (
    <div style={{ background:"rgba(5,14,26,0.98)", border:"1px solid #1e4d6b", borderRadius:10, padding:"10px 16px", color:"#e0f4ff", fontSize:12 }}>
      <div style={{ fontWeight:700, marginBottom:6, color:"#7dd3fc" }}>{label}</div>
      {payload.map((p,i) => (
        <div key={i} style={{ color:p.color, marginBottom:2 }}>
          {p.name}: <b>{p.value != null ? p.value : "—"}{p.unit||""}</b>
        </div>
      ))}
    </div>
  );
};

const inputStyle = { background:"rgba(255,255,255,0.06)", border:"1px solid #1e4d6b", borderRadius:8, color:"#e0f4ff", padding:"7px 12px", fontSize:13, fontFamily:"Georgia,serif", outline:"none", colorScheme:"dark" };
const tabBtn = (active, color="#7dd3fc") => ({ padding:"6px 14px", borderRadius:7, border:"none", background:active?"#0c3a5e":"transparent", color:active?color:"#4a8aaa", cursor:"pointer", fontSize:12, fontFamily:"inherit", transition:"all 0.15s" });
const box = { background:"rgba(255,255,255,0.025)", border:"1px solid #102d4a", borderRadius:16, padding:"20px 16px 16px", marginBottom:18 };

// ── MAIN COMPONENT ────────────────────────────────────────────────────────────
export default function KhulnaHeatStress() {
  const [rawData, setRawData]   = useState(null);
  const [loading, setLoading]   = useState(true);
  const [error, setError]       = useState(null);
  const [downloading, setDownloading] = useState(false);

  const todayStr = new Date().toISOString().split("T")[0];
  const [startDate, setStartDate] = useState("2019-01-01");
  const [endDate, setEndDate]     = useState(todayStr);
  const [tab, setTab]   = useState("heatstroke"); // heatstroke | wetbulb | temp | humidity | solar | trend
  const [view, setView] = useState("monthly");
  const years = ["2019","2020","2021","2022","2023","2024","2025","2026"];
  const currentYear = new Date().getFullYear().toString();

  useEffect(() => {
    (async () => {
      try {
        const url = `https://archive-api.open-meteo.com/v1/archive?latitude=${KHULNA_LAT}&longitude=${KHULNA_LON}&start_date=2019-01-01&end_date=${todayStr}&daily=temperature_2m_max,temperature_2m_min,temperature_2m_mean,relative_humidity_2m_mean,shortwave_radiation_sum&timezone=Asia%2FDhaka`;
        const res  = await fetch(url);
        const json = await res.json();
        setRawData(json);
      } catch { setError("Failed to fetch ERA5 data."); }
      finally  { setLoading(false); }
    })();
  }, []);

  const allDailyRows = useMemo(() => {
    if (!rawData) return [];
    return rawData.daily.time.map((d, i) => {
      const T   = rawData.daily.temperature_2m_mean[i];
      const RH  = rawData.daily.relative_humidity_2m_mean[i];
      const tw  = calcWetBulb(T, RH);
      const wbgt = calcWBGT(T, RH);
      return {
        date: d,
        maxTemp:  rawData.daily.temperature_2m_max[i],
        minTemp:  rawData.daily.temperature_2m_min[i],
        meanTemp: T,
        humidity: RH,
        solar:    rawData.daily.shortwave_radiation_sum[i],
        wetBulb:  tw,
        wbgt:     wbgt,
        wbgtRisk: getWBGTRisk(wbgt).level,
      };
    });
  }, [rawData]);

  const filteredRows = useMemo(() =>
    allDailyRows.filter(r => r.date >= startDate && r.date <= endDate),
    [allDailyRows, startDate, endDate]
  );

  const monthlyData = useMemo(() => groupByMonth(filteredRows), [filteredRows]);
  const yearlyData  = useMemo(() => groupByYear(filteredRows),  [filteredRows]);
  const chartData   = view === "monthly"
    ? monthlyData
    : filteredRows.map(r => ({ ...r, label: r.date.slice(5) }));

  // ── STATS ──
  const allTw    = filteredRows.map(r => r.wetBulb).filter(Boolean);
  const allWbgt  = filteredRows.map(r => r.wbgt).filter(Boolean);
  const allTemps = filteredRows.map(r => r.meanTemp).filter(Boolean);
  const allHum   = filteredRows.map(r => r.humidity).filter(Boolean);
  const allSolar = filteredRows.map(r => r.solar).filter(Boolean);

  const dangerDays  = filteredRows.filter(r => r.wbgt >= 32 && r.wbgt < 35).length;
  const extremeDays = filteredRows.filter(r => r.wbgt >= 35).length;
  const cautionDays = filteredRows.filter(r => r.wbgt >= 28 && r.wbgt < 32).length;
  const maxTw       = allTw.length ? Math.max(...allTw).toFixed(1) : "—";
  const maxWbgt     = allWbgt.length ? Math.max(...allWbgt).toFixed(1) : "—";

  // ── QUICK SELECTS ──
  const setYear    = y => { setStartDate(`${y}-01-01`); setEndDate(y === currentYear ? todayStr : `${y}-12-31`); };
  const setAllTime = () => { setStartDate("2019-01-01"); setEndDate(todayStr); };
  const isAllTime  = startDate === "2019-01-01" && endDate === todayStr;
  const isYear     = y => startDate === `${y}-01-01` && (endDate === `${y}-12-31` || (y === currentYear && endDate === todayStr));

  // ── EXCEL DOWNLOAD ──
  const downloadExcel = () => {
    setDownloading(true);
    try {
      const wb = XLSX.utils.book_new();

      // Daily
      const ws1 = XLSX.utils.aoa_to_sheet([
        ["Date","Max Temp (°C)","Min Temp (°C)","Mean Temp (°C)","Humidity (%)","Solar (MJ/m²)","Wet Bulb Temp (°C)","WBGT (°C)","Heat Stroke Risk"],
        ...filteredRows.map(r => [r.date, r.maxTemp, r.minTemp, r.meanTemp, r.humidity, r.solar, r.wetBulb, r.wbgt, r.wbgtRisk])
      ]);
      ws1["!cols"] = [12,14,14,15,12,14,18,12,16].map(w=>({wch:w}));
      XLSX.utils.book_append_sheet(wb, ws1, "Daily Data");

      // Monthly
      const ws2 = XLSX.utils.aoa_to_sheet([
        ["Month","Avg Max T (°C)","Avg Min T (°C)","Avg Mean T (°C)","Avg Humidity (%)","Avg Solar (MJ/m²)","Avg Wet Bulb (°C)","Avg WBGT (°C)","Danger Days (≥32)","Extreme Days (≥35)"],
        ...monthlyData.map(m => [m.label, m.maxTemp, m.minTemp, m.meanTemp, m.humidity, m.solar, m.wetBulb, m.wbgt, m.dangerDays, m.extremeDays])
      ]);
      ws2["!cols"] = [14,15,15,15,16,16,17,14,18,18].map(w=>({wch:w}));
      XLSX.utils.book_append_sheet(wb, ws2, "Monthly Averages");

      // Yearly Risk Summary
      const ws3 = XLSX.utils.aoa_to_sheet([
        ["Year","Avg Wet Bulb (°C)","Avg WBGT (°C)","Caution Days (28–32°C)","Danger Days (32–35°C)","Extreme Days (≥35°C)","Total Days"],
        ...yearlyData.map(y => [y.year, y.avgTw, y.avgWbgt, y.cautionDays, y.dangerDays, y.extremeDays, y.totalDays])
      ]);
      ws3["!cols"] = [8,18,14,22,22,22,12].map(w=>({wch:w}));
      XLSX.utils.book_append_sheet(wb, ws3, "Yearly Risk Summary");

      // Summary & Citation
      const ws4 = XLSX.utils.aoa_to_sheet([
        ["Metric","Value"],
        ["Study Area","Khulna, Bangladesh"],
        ["Coordinates",`${KHULNA_LAT}°N, ${KHULNA_LON}°E`],
        ["Data Range",`${startDate} to ${endDate}`],
        ["Total Days Analyzed", filteredRows.length],
        ["",""],
        ["Avg Mean Temperature (°C)", avg(allTemps)],
        ["Avg Humidity (%)", avg(allHum)],
        ["Avg Wet Bulb Temperature (°C)", avg(allTw)],
        ["Max Wet Bulb Temperature (°C)", maxTw],
        ["Avg WBGT (°C)", avg(allWbgt)],
        ["Max WBGT (°C)", maxWbgt],
        ["",""],
        ["Caution Days WBGT 28–32°C", cautionDays],
        ["Danger Days WBGT 32–35°C", dangerDays],
        ["Extreme Days WBGT ≥35°C", extremeDays],
        ["",""],
        ["Wet Bulb Formula","Stull (2011) - Journal of Applied Meteorology"],
        ["WBGT Formula","Bernard & Pourmoghani (1999) simplified outdoor WBGT"],
        ["Data Source","ERA5 Reanalysis, ECMWF via Open-Meteo API"],
        ["ERA5 Citation","Hersbach et al. (2020), QJRMS. doi:10.1002/qj.3803"],
        ["Stull Citation","Stull, R. (2011). Wet-Bulb Temperature from Relative Humidity and Air Temperature. J. Appl. Meteor. Climatol., 50, 2267–2269."],
        ["Raymond Citation","Raymond et al. (2020). The emergence of heat and humidity too severe for human tolerance. Science Advances, 6(19)."],
        ["Downloaded on", new Date().toLocaleDateString()],
      ]);
      ws4["!cols"] = [{ wch:32 }, { wch:70 }];
      XLSX.utils.book_append_sheet(wb, ws4, "Summary & Citations");

      XLSX.writeFile(wb, `Khulna_HeatStress_${startDate}_to_${endDate}.xlsx`);
    } catch(e) { alert("Download failed: " + e.message); }
    finally { setDownloading(false); }
  };

  // ── RENDER ────────────────────────────────────────────────────────────────
  const interval = v => Math.max(0, Math.floor(v/14)-1);

  return (
    <div style={{ minHeight:"100vh", background:"linear-gradient(160deg,#04080f 0%,#060d1a 50%,#080f1f 100%)", fontFamily:"Georgia,serif", color:"#cce8f8", paddingBottom:56 }}>

      {/* ── HEADER ── */}
      <div style={{ padding:"22px 24px 16px", borderBottom:"1px solid #0f2a3f", background:"rgba(0,0,0,0.4)", backdropFilter:"blur(10px)", position:"sticky", top:0, zIndex:20 }}>
        <div style={{ maxWidth:1020, margin:"0 auto", display:"flex", alignItems:"center", justifyContent:"space-between", flexWrap:"wrap", gap:12 }}>
          <div>
            <div style={{ fontSize:10, letterSpacing:4, color:"#ef4444", textTransform:"uppercase", marginBottom:2 }}>Heat Stress Research · Khulna, Bangladesh</div>
            <h1 style={{ margin:0, fontSize:24, fontWeight:700, color:"#fff", letterSpacing:-0.5 }}>
              🌡️ Khulna Heat Stroke Risk Index
            </h1>
            <div style={{ fontSize:12, color:"#64a7c8", marginTop:2 }}>
              Wet Bulb Temperature · WBGT · ERA5 Reanalysis · 2019–Present
            </div>
          </div>
          <button onClick={downloadExcel} disabled={downloading || !filteredRows.length} style={{
            display:"flex", alignItems:"center", gap:8, padding:"9px 18px", borderRadius:10,
            border:"1px solid #ef4444", background: "linear-gradient(135deg,#3b0000,#5c0a0a)",
            color:"#fca5a5", cursor:"pointer", fontSize:13, fontFamily:"inherit", fontWeight:600,
            boxShadow:"0 2px 16px rgba(239,68,68,0.25)"
          }}>
            <span>📥</span> {downloading ? "Exporting…" : `Download Excel (${filteredRows.length.toLocaleString()} days)`}
          </button>
        </div>
      </div>

      <div style={{ maxWidth:1020, margin:"0 auto", padding:"0 16px" }}>

        {/* ── DATE FILTER ── */}
        <div style={{ ...box, marginTop:20, padding:"18px 20px" }}>
          <div style={{ fontSize:10, color:"#38bdf8", letterSpacing:3, textTransform:"uppercase", marginBottom:12 }}>📅 Date Range Filter</div>
          <div style={{ display:"flex", flexWrap:"wrap", gap:12, alignItems:"flex-end" }}>
            <div>
              <div style={{ fontSize:10, color:"#4a8aaa", marginBottom:4 }}>START DATE</div>
              <input type="date" value={startDate} min="2019-01-01" max={endDate} onChange={e=>setStartDate(e.target.value)} style={inputStyle}/>
            </div>
            <div style={{ color:"#1e4d6b", fontSize:18, paddingBottom:2 }}>→</div>
            <div>
              <div style={{ fontSize:10, color:"#4a8aaa", marginBottom:4 }}>END DATE</div>
              <input type="date" value={endDate} min={startDate} max={todayStr} onChange={e=>setEndDate(e.target.value)} style={inputStyle}/>
            </div>
            <div style={{ width:1, height:34, background:"#0f3455", alignSelf:"center" }}/>
            <div>
              <div style={{ fontSize:10, color:"#4a8aaa", marginBottom:4 }}>QUICK SELECT</div>
              <div style={{ display:"flex", gap:5, flexWrap:"wrap" }}>
                <button onClick={setAllTime} style={{ padding:"5px 11px", borderRadius:7, border:`1px solid ${isAllTime?"#38bdf8":"#1e4d6b"}`, background:isAllTime?"#0c3a5e":"transparent", color:isAllTime?"#7dd3fc":"#4a8aaa", cursor:"pointer", fontSize:11, fontFamily:"inherit" }}>All</button>
                {years.map(y=>(
                  <button key={y} onClick={()=>setYear(y)} style={{ padding:"5px 11px", borderRadius:7, border:`1px solid ${isYear(y)?"#38bdf8":"#1e4d6b"}`, background:isYear(y)?"#0c3a5e":"transparent", color:isYear(y)?"#7dd3fc":"#4a8aaa", cursor:"pointer", fontSize:11, fontFamily:"inherit" }}>{y}</button>
                ))}
              </div>
            </div>
          </div>
          {filteredRows.length > 0 && (
            <div style={{ marginTop:8, fontSize:11, color:"#4a8aaa" }}>
              Showing <b style={{ color:"#7dd3fc" }}>{filteredRows.length.toLocaleString()} days</b> · {startDate} → {endDate}
            </div>
          )}
        </div>

        {loading && <div style={{ textAlign:"center", padding:"80px 0", color:"#38bdf8" }}><div style={{ fontSize:44 }}>🌀</div><div style={{ marginTop:12, letterSpacing:2 }}>Loading ERA5 archive…</div></div>}
        {error   && <div style={{ textAlign:"center", padding:"60px 0", color:"#f87171" }}><div style={{ fontSize:32 }}>⚠️</div><div style={{ marginTop:10 }}>{error}</div></div>}

        {!loading && !error && filteredRows.length > 0 && (<>

          {/* ── RISK STAT CARDS ── */}
          <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fit,minmax(155px,1fr))", gap:12, marginBottom:18 }}>
            {[
              { label:"Avg Wet Bulb Temp",   value: avg(allTw)    != null ? avg(allTw)+"°C"    : "—", icon:"💧", color:"#38bdf8", sub:"Stull (2011)" },
              { label:"Max Wet Bulb Temp",   value: maxTw+"°C",                                         icon:"⚠️", color:"#f97316", sub:"Peak survival stress" },
              { label:"Avg WBGT",            value: avg(allWbgt)  != null ? avg(allWbgt)+"°C"  : "—", icon:"🌡️", color:"#facc15", sub:"Heat stroke index" },
              { label:"Danger Days ≥32°C",   value: dangerDays,                                          icon:"🟠", color:"#f97316", sub:"WBGT 32–35°C" },
              { label:"Extreme Days ≥35°C",  value: extremeDays,                                         icon:"🔴", color:"#ef4444", sub:"Life-threatening" },
              { label:"Caution Days ≥28°C",  value: cautionDays,                                         icon:"🟡", color:"#facc15", sub:"WBGT 28–32°C" },
            ].map((s,i) => (
              <div key={i} style={{ background:"rgba(255,255,255,0.04)", border:"1px solid #1a3a50", borderRadius:14, padding:"14px 16px" }}>
                <div style={{ fontSize:20, marginBottom:5 }}>{s.icon}</div>
                <div style={{ fontSize:20, fontWeight:700, color:s.color }}>{s.value}</div>
                <div style={{ fontSize:11, color:"#94a3b8", marginTop:3 }}>{s.label}</div>
                <div style={{ fontSize:10, color:"#4a6a7a", marginTop:2, fontStyle:"italic" }}>{s.sub}</div>
              </div>
            ))}
          </div>

          {/* ── RISK LEGEND ── */}
          <div style={{ ...box, padding:"14px 20px" }}>
            <div style={{ fontSize:10, color:"#94a3b8", letterSpacing:3, textTransform:"uppercase", marginBottom:10 }}>WBGT Heat Stroke Risk Scale</div>
            <div style={{ display:"flex", flexWrap:"wrap", gap:8 }}>
              {[
                { range:"< 28°C",   label:"Safe",     color:"#4ade80", desc:"Normal activity" },
                { range:"28–32°C",  label:"Caution",  color:"#facc15", desc:"Risk for elderly/sick" },
                { range:"32–35°C",  label:"Danger",   color:"#f97316", desc:"Limit outdoor work" },
                { range:"≥ 35°C",   label:"Extreme",  color:"#ef4444", desc:"Life-threatening" },
              ].map((r,i) => (
                <div key={i} style={{ display:"flex", alignItems:"center", gap:7, background:"rgba(255,255,255,0.03)", border:`1px solid ${r.color}33`, borderRadius:8, padding:"6px 12px" }}>
                  <div style={{ width:10, height:10, borderRadius:"50%", background:r.color, flexShrink:0 }}/>
                  <span style={{ color:r.color, fontWeight:600, fontSize:12 }}>{r.label}</span>
                  <span style={{ color:"#64a7c8", fontSize:11 }}>{r.range}</span>
                  <span style={{ color:"#4a6a7a", fontSize:10 }}>· {r.desc}</span>
                </div>
              ))}
            </div>
          </div>

          {/* ── VIEW & TAB CONTROLS ── */}
          <div style={{ display:"flex", gap:8, marginBottom:14, flexWrap:"wrap", alignItems:"center", justifyContent:"space-between" }}>
            <div style={{ display:"flex", gap:3, background:"rgba(255,255,255,0.04)", borderRadius:10, padding:4, border:"1px solid #0f3455" }}>
              {[["monthly","Monthly Avg"],["daily","Daily View"]].map(([v,l])=>(
                <button key={v} onClick={()=>setView(v)} style={{ padding:"6px 14px", borderRadius:7, border:"none", background:view===v?"#0c3a5e":"transparent", color:view===v?"#7dd3fc":"#4a8aaa", cursor:"pointer", fontSize:12, fontFamily:"inherit" }}>{l}</button>
              ))}
            </div>
            <div style={{ display:"flex", gap:3, background:"rgba(255,255,255,0.04)", borderRadius:10, padding:4, border:"1px solid #0f3455", flexWrap:"wrap" }}>
              {[["heatstroke","🔴 Heat Stroke Risk"],["wetbulb","💧 Wet Bulb Temp"],["trend","📈 Year Trend"],["temp","🌡️ Temperature"],["humidity","💧 Humidity"],["solar","☀️ Solar"]].map(([v,l])=>(
                <button key={v} onClick={()=>setTab(v)} style={tabBtn(tab===v, tab===v&&v==="heatstroke"?"#fca5a5":"#7dd3fc")}>{l}</button>
              ))}
            </div>
          </div>

          {/* ── HEAT STROKE RISK CHART ── */}
          {tab === "heatstroke" && (
            <div style={box}>
              <div style={{ paddingLeft:8, marginBottom:12 }}>
                <div style={{ fontSize:10, color:"#ef4444", letterSpacing:3, textTransform:"uppercase" }}>Heat Stroke Risk Index (WBGT)</div>
                <div style={{ fontSize:15, fontWeight:700, color:"#e0f4ff", marginTop:3 }}>
                  {view==="monthly" ? "Monthly Average WBGT — Danger Days" : "Daily WBGT Values"}
                </div>
                <div style={{ fontSize:11, color:"#6b7280", marginTop:2 }}>Bernard & Pourmoghani (1999) simplified outdoor WBGT</div>
              </div>
              <ResponsiveContainer width="100%" height={300}>
                {view === "monthly" ? (
                  <ComposedChart data={monthlyData} margin={{ top:5, right:16, left:0, bottom:5 }}>
                    <CartesianGrid stroke="#0f1f30" strokeDasharray="3 3"/>
                    <XAxis dataKey="label" tick={{ fill:"#4a8aaa", fontSize:10 }} interval={interval(monthlyData.length)}/>
                    <YAxis yAxisId="left" tick={{ fill:"#4a8aaa", fontSize:10 }} unit="°C" domain={[20,40]}/>
                    <YAxis yAxisId="right" orientation="right" tick={{ fill:"#4a8aaa", fontSize:10 }} unit=" days"/>
                    <Tooltip content={<CustomTooltip/>}/>
                    <Legend wrapperStyle={{ color:"#94a3b8", fontSize:11 }}/>
                    <ReferenceLine yAxisId="left" y={35} stroke="#ef4444" strokeDasharray="5 3" label={{ value:"Extreme ≥35°C", fill:"#ef4444", fontSize:10, position:"insideTopLeft" }}/>
                    <ReferenceLine yAxisId="left" y={32} stroke="#f97316" strokeDasharray="5 3" label={{ value:"Danger ≥32°C", fill:"#f97316", fontSize:10, position:"insideTopLeft" }}/>
                    <ReferenceLine yAxisId="left" y={28} stroke="#facc15" strokeDasharray="5 3" label={{ value:"Caution ≥28°C", fill:"#facc15", fontSize:10, position:"insideTopLeft" }}/>
                    <Area yAxisId="left" type="monotone" dataKey="wbgt" name="Avg WBGT" stroke="#f97316" fill="#f9731625" strokeWidth={2} dot={false} unit="°C"/>
                    <Bar yAxisId="right" dataKey="dangerDays" name="Danger Days" fill="#ef444455" radius={[3,3,0,0]} unit=" days"/>
                  </ComposedChart>
                ) : (
                  <AreaChart data={chartData} margin={{ top:5, right:16, left:0, bottom:5 }}>
                    <defs>
                      <linearGradient id="gWbgt" x1="0" y1="0" x2="0" y2="1">
                        <stop offset="5%" stopColor="#f97316" stopOpacity={0.4}/><stop offset="95%" stopColor="#f97316" stopOpacity={0.02}/>
                      </linearGradient>
                    </defs>
                    <CartesianGrid stroke="#0f1f30" strokeDasharray="3 3"/>
                    <XAxis dataKey="label" tick={{ fill:"#4a8aaa", fontSize:10 }} interval={interval(filteredRows.length)}/>
                    <YAxis tick={{ fill:"#4a8aaa", fontSize:10 }} unit="°C" domain={[18,42]}/>
                    <Tooltip content={<CustomTooltip/>}/>
                    <ReferenceLine y={35} stroke="#ef4444" strokeDasharray="4 2"/>
                    <ReferenceLine y={32} stroke="#f97316" strokeDasharray="4 2"/>
                    <ReferenceLine y={28} stroke="#facc15" strokeDasharray="4 2"/>
                    <Area type="monotone" dataKey="wbgt" name="WBGT" stroke="#f97316" fill="url(#gWbgt)" strokeWidth={1.5} dot={false} unit="°C"/>
                  </AreaChart>
                )}
              </ResponsiveContainer>
            </div>
          )}

          {/* ── WET BULB CHART ── */}
          {tab === "wetbulb" && (
            <div style={box}>
              <div style={{ paddingLeft:8, marginBottom:12 }}>
                <div style={{ fontSize:10, color:"#38bdf8", letterSpacing:3, textTransform:"uppercase" }}>Wet Bulb Temperature (Tw)</div>
                <div style={{ fontSize:15, fontWeight:700, color:"#e0f4ff", marginTop:3 }}>{view==="monthly" ? "Monthly Average Tw" : "Daily Tw"}</div>
                <div style={{ fontSize:11, color:"#6b7280", marginTop:2 }}>Stull (2011) formula · Survival limit = 35°C (Raymond et al. 2020)</div>
              </div>
              <ResponsiveContainer width="100%" height={280}>
                <AreaChart data={chartData} margin={{ top:5, right:16, left:0, bottom:5 }}>
                  <defs>
                    <linearGradient id="gTw" x1="0" y1="0" x2="0" y2="1">
                      <stop offset="5%" stopColor="#38bdf8" stopOpacity={0.35}/><stop offset="95%" stopColor="#38bdf8" stopOpacity={0.02}/>
                    </linearGradient>
                  </defs>
                  <CartesianGrid stroke="#0f1f30" strokeDasharray="3 3"/>
                  <XAxis dataKey="label" tick={{ fill:"#4a8aaa", fontSize:10 }} interval={interval(chartData.length)}/>
                  <YAxis tick={{ fill:"#4a8aaa", fontSize:10 }} unit="°C" domain={[10,38]}/>
                  <Tooltip content={<CustomTooltip/>}/>
                  <Legend wrapperStyle={{ color:"#94a3b8", fontSize:11 }}/>
                  <ReferenceLine y={35} stroke="#ef4444" strokeWidth={2} strokeDasharray="5 3" label={{ value:"☠ Lethal limit 35°C (Raymond et al. 2020)", fill:"#ef4444", fontSize:10, position:"insideTopLeft" }}/>
                  <ReferenceLine y={32} stroke="#f97316" strokeDasharray="4 2" label={{ value:"Dangerous 32°C", fill:"#f97316", fontSize:10, position:"insideTopLeft" }}/>
                  <ReferenceLine y={28} stroke="#facc15" strokeDasharray="4 2"/>
                  <Area type="monotone" dataKey="wetBulb" name="Wet Bulb Temp" stroke="#38bdf8" fill="url(#gTw)" strokeWidth={2} dot={false} unit="°C"/>
                </AreaChart>
              </ResponsiveContainer>
            </div>
          )}

          {/* ── YEARLY TREND CHART ── */}
          {tab === "trend" && (
            <div style={box}>
              <div style={{ paddingLeft:8, marginBottom:12 }}>
                <div style={{ fontSize:10, color:"#a78bfa", letterSpacing:3, textTransform:"uppercase" }}>Year-by-Year Trend Analysis</div>
                <div style={{ fontSize:15, fontWeight:700, color:"#e0f4ff", marginTop:3 }}>Heat Risk Days per Year — Is Khulna Getting Worse?</div>
                <div style={{ fontSize:11, color:"#6b7280", marginTop:2 }}>Number of days in each WBGT risk category per calendar year</div>
              </div>
              <ResponsiveContainer width="100%" height={300}>
                <BarChart data={yearlyData} margin={{ top:5, right:16, left:0, bottom:5 }}>
                  <CartesianGrid stroke="#0f1f30" strokeDasharray="3 3"/>
                  <XAxis dataKey="year" tick={{ fill:"#4a8aaa", fontSize:11 }}/>
                  <YAxis tick={{ fill:"#4a8aaa", fontSize:10 }} unit=" days"/>
                  <Tooltip content={<CustomTooltip/>}/>
                  <Legend wrapperStyle={{ color:"#94a3b8", fontSize:11 }}/>
                  <Bar dataKey="cautionDays" name="Caution (28–32°C)" stackId="a" fill="#facc15" unit=" days"/>
                  <Bar dataKey="dangerDays"  name="Danger (32–35°C)"  stackId="a" fill="#f97316" unit=" days"/>
                  <Bar dataKey="extremeDays" name="Extreme (≥35°C)"   stackId="a" fill="#ef4444" radius={[4,4,0,0]} unit=" days"/>
                </BarChart>
              </ResponsiveContainer>
              <div style={{ marginTop:16 }}>
                <div style={{ fontSize:10, color:"#a78bfa", letterSpacing:3, textTransform:"uppercase", marginBottom:10 }}>Avg Wet Bulb Temp per Year</div>
                <ResponsiveContainer width="100%" height={180}>
                  <LineChart data={yearlyData} margin={{ top:5, right:16, left:0, bottom:5 }}>
                    <CartesianGrid stroke="#0f1f30" strokeDasharray="3 3"/>
                    <XAxis dataKey="year" tick={{ fill:"#4a8aaa", fontSize:11 }}/>
                    <YAxis tick={{ fill:"#4a8aaa", fontSize:10 }} unit="°C" domain={["auto","auto"]}/>
                    <Tooltip content={<CustomTooltip/>}/>
                    <ReferenceLine y={35} stroke="#ef4444" strokeDasharray="4 2" label={{ value:"Lethal 35°C", fill:"#ef4444", fontSize:10 }}/>
                    <Line type="monotone" dataKey="avgTw" name="Avg Wet Bulb Temp" stroke="#38bdf8" strokeWidth={2.5} dot={{ fill:"#38bdf8", r:5 }} unit="°C"/>
                    <Line type="monotone" dataKey="avgWbgt" name="Avg WBGT" stroke="#f97316" strokeWidth={2} dot={{ fill:"#f97316", r:4 }} unit="°C" strokeDasharray="5 3"/>
                  </LineChart>
                </ResponsiveContainer>
              </div>
            </div>
          )}

          {/* ── TEMPERATURE CHART ── */}
          {tab === "temp" && (
            <div style={box}>
              <div style={{ paddingLeft:8, marginBottom:12 }}>
                <div style={{ fontSize:10, color:"#fb923c", letterSpacing:3, textTransform:"uppercase" }}>Surface Temperature</div>
                <div style={{ fontSize:15, fontWeight:700, color:"#e0f4ff", marginTop:3 }}>{view==="monthly" ? "Monthly Averages" : "Daily Records"}</div>
              </div>
              <ResponsiveContainer width="100%" height={260}>
                {view === "monthly" ? (
                  <AreaChart data={monthlyData} margin={{ top:5, right:16, left:0, bottom:5 }}>
                    <defs>
                      <linearGradient id="gMx" x1="0" y1="0" x2="0" y2="1"><stop offset="5%" stopColor="#f97316" stopOpacity={0.3}/><stop offset="95%" stopColor="#f97316" stopOpacity={0}/></linearGradient>
                      <linearGradient id="gMn" x1="0" y1="0" x2="0" y2="1"><stop offset="5%" stopColor="#38bdf8" stopOpacity={0.2}/><stop offset="95%" stopColor="#38bdf8" stopOpacity={0}/></linearGradient>
                    </defs>
                    <CartesianGrid stroke="#0f1f30" strokeDasharray="3 3"/>
                    <XAxis dataKey="label" tick={{ fill:"#4a8aaa", fontSize:10 }} interval={interval(monthlyData.length)}/>
                    <YAxis tick={{ fill:"#4a8aaa", fontSize:10 }} unit="°C" domain={[10,42]}/>
                    <Tooltip content={<CustomTooltip/>}/><Legend wrapperStyle={{ color:"#94a3b8", fontSize:11 }}/>
                    <Area type="monotone" dataKey="maxTemp" name="Max Temp" stroke="#f97316" fill="url(#gMx)" strokeWidth={2} dot={false} unit="°C"/>
                    <Area type="monotone" dataKey="meanTemp" name="Mean Temp" stroke="#facc15" fill="none" strokeWidth={1.5} dot={false} unit="°C" strokeDasharray="4 2"/>
                    <Area type="monotone" dataKey="minTemp" name="Min Temp" stroke="#38bdf8" fill="url(#gMn)" strokeWidth={2} dot={false} unit="°C"/>
                  </AreaChart>
                ) : (
                  <ComposedChart data={chartData} margin={{ top:5, right:16, left:0, bottom:5 }}>
                    <CartesianGrid stroke="#0f1f30" strokeDasharray="3 3"/>
                    <XAxis dataKey="label" tick={{ fill:"#4a8aaa", fontSize:10 }} interval={interval(filteredRows.length)}/>
                    <YAxis tick={{ fill:"#4a8aaa", fontSize:10 }} unit="°C" domain={[10,45]}/>
                    <Tooltip content={<CustomTooltip/>}/><Legend wrapperStyle={{ color:"#94a3b8", fontSize:11 }}/>
                    <Area type="monotone" dataKey="maxTemp" name="Max Temp" stroke="#f97316" fill="#f9731618" strokeWidth={1.5} dot={false} unit="°C"/>
                    <Area type="monotone" dataKey="minTemp" name="Min Temp" stroke="#38bdf8" fill="#38bdf818" strokeWidth={1.5} dot={false} unit="°C"/>
                  </ComposedChart>
                )}
              </ResponsiveContainer>
            </div>
          )}

          {/* ── HUMIDITY CHART ── */}
          {tab === "humidity" && (
            <div style={box}>
              <div style={{ paddingLeft:8, marginBottom:12 }}>
                <div style={{ fontSize:10, color:"#38bdf8", letterSpacing:3, textTransform:"uppercase" }}>Relative Humidity</div>
                <div style={{ fontSize:15, fontWeight:700, color:"#e0f4ff", marginTop:3 }}>{view==="monthly" ? "Monthly Averages" : "Daily Records"}</div>
              </div>
              <ResponsiveContainer width="100%" height={240}>
                {view === "monthly" ? (
                  <BarChart data={monthlyData} margin={{ top:5, right:16, left:0, bottom:5 }}>
                    <CartesianGrid stroke="#0f1f30" strokeDasharray="3 3"/>
                    <XAxis dataKey="label" tick={{ fill:"#4a8aaa", fontSize:10 }} interval={interval(monthlyData.length)}/>
                    <YAxis tick={{ fill:"#4a8aaa", fontSize:10 }} unit="%" domain={[40,100]}/>
                    <Tooltip content={<CustomTooltip/>}/>
                    <ReferenceLine y={80} stroke="#7dd3fc" strokeDasharray="4 2" label={{ value:"Monsoon ~80%", fill:"#7dd3fc", fontSize:10, position:"insideTopLeft" }}/>
                    <Bar dataKey="humidity" name="Avg Humidity" fill="#0ea5e9" radius={[4,4,0,0]} unit="%"/>
                  </BarChart>
                ) : (
                  <AreaChart data={chartData} margin={{ top:5, right:16, left:0, bottom:5 }}>
                    <defs><linearGradient id="gHm" x1="0" y1="0" x2="0" y2="1"><stop offset="5%" stopColor="#0ea5e9" stopOpacity={0.4}/><stop offset="95%" stopColor="#0ea5e9" stopOpacity={0.03}/></linearGradient></defs>
                    <CartesianGrid stroke="#0f1f30" strokeDasharray="3 3"/>
                    <XAxis dataKey="label" tick={{ fill:"#4a8aaa", fontSize:10 }} interval={interval(filteredRows.length)}/>
                    <YAxis tick={{ fill:"#4a8aaa", fontSize:10 }} unit="%" domain={[30,100]}/>
                    <Tooltip content={<CustomTooltip/>}/>
                    <Area type="monotone" dataKey="humidity" name="Humidity" stroke="#0ea5e9" fill="url(#gHm)" strokeWidth={1.5} dot={false} unit="%"/>
                  </AreaChart>
                )}
              </ResponsiveContainer>
            </div>
          )}

          {/* ── SOLAR CHART ── */}
          {tab === "solar" && (
            <div style={box}>
              <div style={{ paddingLeft:8, marginBottom:12 }}>
                <div style={{ fontSize:10, color:"#fbbf24", letterSpacing:3, textTransform:"uppercase" }}>Solar Radiation</div>
                <div style={{ fontSize:15, fontWeight:700, color:"#e0f4ff", marginTop:3 }}>{view==="monthly" ? "Monthly Avg Daily Radiation" : "Daily Shortwave Radiation"} · MJ/m²</div>
              </div>
              <ResponsiveContainer width="100%" height={240}>
                {view === "monthly" ? (
                  <BarChart data={monthlyData} margin={{ top:5, right:16, left:0, bottom:5 }}>
                    <CartesianGrid stroke="#0f1f30" strokeDasharray="3 3"/>
                    <XAxis dataKey="label" tick={{ fill:"#4a8aaa", fontSize:10 }} interval={interval(monthlyData.length)}/>
                    <YAxis tick={{ fill:"#4a8aaa", fontSize:10 }} unit=" MJ" domain={[0,30]}/>
                    <Tooltip content={<CustomTooltip/>}/>
                    <Bar dataKey="solar" name="Solar Radiation" fill="#f59e0b" radius={[4,4,0,0]} unit=" MJ/m²"/>
                  </BarChart>
                ) : (
                  <AreaChart data={chartData} margin={{ top:5, right:16, left:0, bottom:5 }}>
                    <defs><linearGradient id="gSl" x1="0" y1="0" x2="0" y2="1"><stop offset="5%" stopColor="#f59e0b" stopOpacity={0.4}/><stop offset="95%" stopColor="#f59e0b" stopOpacity={0.02}/></linearGradient></defs>
                    <CartesianGrid stroke="#0f1f30" strokeDasharray="3 3"/>
                    <XAxis dataKey="label" tick={{ fill:"#4a8aaa", fontSize:10 }} interval={interval(filteredRows.length)}/>
                    <YAxis tick={{ fill:"#4a8aaa", fontSize:10 }} unit=" MJ" domain={[0,35]}/>
                    <Tooltip content={<CustomTooltip/>}/>
                    <Area type="monotone" dataKey="solar" name="Solar Radiation" stroke="#f59e0b" fill="url(#gSl)" strokeWidth={1.5} dot={false} unit=" MJ/m²"/>
                  </AreaChart>
                )}
              </ResponsiveContainer>
            </div>
          )}

          {/* ── YEARLY RISK TABLE ── */}
          {tab === "trend" && yearlyData.length > 0 && (
            <div style={box}>
              <div style={{ fontSize:10, color:"#a78bfa", letterSpacing:3, textTransform:"uppercase", marginBottom:14 }}>Annual Risk Summary Table</div>
              <div style={{ overflowX:"auto" }}>
                <table style={{ width:"100%", borderCollapse:"collapse", fontSize:12 }}>
                  <thead>
                    <tr style={{ color:"#64a7c8", borderBottom:"1px solid #1e4d6b" }}>
                      {["Year","Avg Tw (°C)","Avg WBGT (°C)","🟡 Caution","🟠 Danger","🔴 Extreme","Total Days"].map((h,i) => (
                        <th key={i} style={{ padding:"8px 12px", textAlign:"left", fontWeight:600, fontSize:11 }}>{h}</th>
                      ))}
                    </tr>
                  </thead>
                  <tbody>
                    {yearlyData.map((y,i) => (
                      <tr key={i} style={{ borderBottom:"1px solid #0f2030", background: i%2===0?"rgba(255,255,255,0.02)":"transparent" }}>
                        <td style={{ padding:"8px 12px", color:"#7dd3fc", fontWeight:700 }}>{y.year}</td>
                        <td style={{ padding:"8px 12px", color:"#38bdf8" }}>{y.avgTw}</td>
                        <td style={{ padding:"8px 12px", color: y.avgWbgt >= 32 ? "#ef4444" : y.avgWbgt >= 28 ? "#f97316" : "#facc15" }}>{y.avgWbgt}</td>
                        <td style={{ padding:"8px 12px", color:"#facc15" }}>{y.cautionDays}</td>
                        <td style={{ padding:"8px 12px", color:"#f97316" }}>{y.dangerDays}</td>
                        <td style={{ padding:"8px 12px", color:"#ef4444", fontWeight: y.extremeDays > 0 ? 700 : 400 }}>{y.extremeDays}</td>
                        <td style={{ padding:"8px 12px", color:"#64a7c8" }}>{y.totalDays}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          {/* ── CITATION BOX ── */}
          <div style={{ ...box, background:"rgba(139,92,246,0.05)", border:"1px solid #4c1d95" }}>
            <div style={{ fontSize:10, color:"#a78bfa", letterSpacing:3, textTransform:"uppercase", marginBottom:10 }}>📚 Cite These in Your Paper</div>
            <div style={{ display:"flex", flexDirection:"column", gap:8 }}>
              {[
                { ref:"ERA5 Data", cite:"Hersbach, H. et al. (2020). The ERA5 global reanalysis. Q. J. R. Meteorol. Soc., 146(730), 1999–2049. doi:10.1002/qj.3803" },
                { ref:"Wet Bulb Formula", cite:"Stull, R. (2011). Wet-Bulb Temperature from Relative Humidity and Air Temperature. J. Appl. Meteor. Climatol., 50, 2267–2269. doi:10.1175/JAMC-D-11-0143.1" },
                { ref:"35°C Survival Limit", cite:"Raymond, C. et al. (2020). The emergence of heat and humidity too severe for human tolerance. Science Advances, 6(19), eaaw1838. doi:10.1126/sciadv.aaw1838" },
                { ref:"WBGT Formula", cite:"Bernard, T.E. & Pourmoghani, M. (1999). Prediction of workplace wet bulb global temperature. Applied Occupational and Environmental Hygiene, 14(2), 126–134." },
              ].map((c,i) => (
                <div key={i} style={{ fontSize:11, color:"#94a3b8", lineHeight:1.6 }}>
                  <span style={{ color:"#a78bfa", fontWeight:600 }}>[{c.ref}]</span> {c.cite}
                </div>
              ))}
            </div>
          </div>

          <div style={{ textAlign:"center", fontSize:10, color:"#1e3a4a", marginTop:4 }}>
            Data: Open-Meteo Archive · ERA5 (ECMWF) · Location: {KHULNA_LAT}°N, {KHULNA_LON}°E
          </div>

        </>)}
      </div>
    </div>
  );
}
